mapper.select:
SELECT cw.计划转移数量
FROM CONTRACT_WASTE_ITEM cw
JOIN CONTRACT c ON cw.合同编号 = c.合同编号
WHERE c.合同号 = #{contractCode}
AND cw.废物类别 = #{wasteCategory}
LIMIT 1

SELECT s.结算单单号 AS settlementCode, s.合同号 AS contractCode, c.甲方名称 AS partyAName, c.甲方统一社会信用代码 AS partyASocialCreditCode, s.结算类型 AS settlementType, s.关联来源类型 AS sourceType, s.结算金额 AS settlementAmount, s.已收金额 AS receivedAmount, s.状态 AS status, s.制单人名称 AS creatorName FROM SETTLEMENT s LEFT JOIN CONTRACT c ON s.合同编号 = c.合同编号
AND s.制单人编码 = #{creatorId}
ORDER BY s.创建时间 DESC, s.结算单编号 DESC

SELECT s.结算单编号, s.结算单单号, s.合同号, s.合同编号, (SELECT c.甲方名称 FROM CONTRACT c WHERE c.合同编号 = s.合同编号 LIMIT 1) 甲方名称, s.结算类型, s.关联来源类型, s.结算金额, s.状态, s.制单人编码, s.制单人名称, s.创建时间, s.审核人编码, e.员工姓名 AS 审核人姓名, s.审核时间, s.审核意见, CASE WHEN bfCount.cnt > 0 THEN TRUE ELSE FALSE END 是否已生成业务结算单, COALESCE(bfCount.cnt, 0) 业务结算单数量 FROM SETTLEMENT s LEFT JOIN EMPLOYEE e ON s.审核人编码 = e.员工编码 LEFT JOIN ( SELECT rel.危废结算单编号 AS 结算单编号, COUNT(*) AS cnt FROM BUSINESS_FEE_SETTLEMENT_REL rel
INNER JOIN BUSINESS_FEE_HEADER bfh ON bfh.业务序号 = rel.业务序号 AND bfh.业务合同编号 = #{req.businessContractId}
INNER JOIN SETTLEMENT sf ON sf.结算单编号 = rel.危废结算单编号 AND sf.合同编号 = #{req.contractId}
GROUP BY rel.危废结算单编号 ) bfCount ON bfCount.结算单编号 = s.结算单编号
AND s.结算单编号 = #{req.settlementId}
AND s.结算单单号 LIKE CONCAT('%', #{req.settlementCode}, '%')
AND s.结算类型 = #{req.settlementType}
AND s.状态 = #{req.status}
AND s.制单人名称 LIKE CONCAT('%', #{req.creatorName}, '%')
AND s.合同编号 = #{req.contractId}
AND s.合同编号 IS NULL
ORDER BY s.创建时间 DESC, s.结算单编号 DESC
